import { useState } from 'react';
import './App.css';

// ─── Data ─────────────────────────────────────────────────────────────────────

const GROUPS = {
  A: ['Mexico', 'South Africa', 'South Korea', 'Czechia'],
  B: ['Canada', 'Bosnia and Herzegovina', 'Qatar', 'Switzerland'],
  C: ['Brazil', 'Morocco', 'Haiti', 'Scotland'],
  D: ['USA', 'Paraguay', 'Australia', 'Türkiye'],
  E: ['Germany', 'Curaçao', 'Ivory Coast', 'Ecuador'],
  F: ['Netherlands', 'Japan', 'Sweden', 'Tunisia'],
  G: ['Belgium', 'Egypt', 'Iran', 'New Zealand'],
  H: ['Spain', 'Cape Verde', 'Saudi Arabia', 'Uruguay'],
  I: ['France', 'Senegal', 'Iraq', 'Norway'],
  J: ['Argentina', 'Algeria', 'Austria', 'Jordan'],
  K: ['Portugal', 'DR Congo', 'Uzbekistan', 'Colombia'],
  L: ['England', 'Croatia', 'Ghana', 'Panama'],
};

const groupMatches = (teams) => [
  [teams[0], teams[1]], [teams[2], teams[3]],
  [teams[0], teams[2]], [teams[1], teams[3]],
  [teams[0], teams[3]], [teams[1], teams[2]],
];

// ─── State helpers ─────────────────────────────────────────────────────────────

const emptyKO = () => ({
  r32: Array(32).fill('TBD'),
  r16: Array(16).fill('TBD'),
  qf: Array(8).fill('TBD'),
  sf: Array(4).fill('TBD'),
  final: ['TBD', 'TBD'],
  third: ['TBD', 'TBD'],
  winner: 'TBD',
  thirdPlace: 'TBD',
});

const emptyData = () => ({ qualifiers: {}, matchResults: {}, knockout: emptyKO() });

// ─── Standings calculation ────────────────────────────────────────────────────

function calcStandings(groupKey, matchResultsForGroup) {
  const teams = GROUPS[groupKey];
  const matches = groupMatches(teams);
  const stats = {};
  teams.forEach((t) => { stats[t] = { w: 0, d: 0, l: 0, gf: 0, ga: 0 }; });

  matches.forEach((match, i) => {
    const res = (matchResultsForGroup || {})[i];
    if (!res) return;
    const [home, away] = match;
    const hg = parseInt(res.homeGoals);
    const ag = parseInt(res.awayGoals);
    const hasScores = !isNaN(hg) && !isNaN(ag);

    if (hasScores) {
      stats[home].gf += hg; stats[home].ga += ag;
      stats[away].gf += ag; stats[away].ga += hg;
      if (hg > ag)      { stats[home].w++; stats[away].l++; }
      else if (hg < ag) { stats[away].w++; stats[home].l++; }
      else              { stats[home].d++; stats[away].d++; }
    } else if (res.result) {
      if (res.result === 'home')      { stats[home].w++; stats[away].l++; }
      else if (res.result === 'away') { stats[away].w++; stats[home].l++; }
      else if (res.result === 'draw') { stats[home].d++; stats[away].d++; }
    }
  });

  return teams
    .map((t) => ({ name: t, ...stats[t], pts: stats[t].w * 3 + stats[t].d }))
    .sort((a, b) => b.pts - a.pts || (b.gf - b.ga) - (a.gf - a.ga) || b.gf - a.gf);
}

// ─── Comparison logic ─────────────────────────────────────────────────────────

// Fixed scoring rules:
// Simple mode:   1pt per correct group position, 1pt per correct KO advance
// Advanced mode: 1pt per correct group position, 1pt per correct KO advance
//                PLUS: 1pt per correct W/D/L, OR 3pts per exact score (mutually exclusive per match)

function ord(n) {
  if (n === 1) return 'st'; if (n === 2) return 'nd'; if (n === 3) return 'rd'; return 'th';
}

function getOutcome(res) {
  if (!res) return { outcome: '', hg: null, ag: null };
  const hg = parseInt(res.homeGoals), ag = parseInt(res.awayGoals);
  if (!isNaN(hg) && !isNaN(ag)) {
    if (hg > ag) return { outcome: 'home', hg, ag };
    if (hg < ag) return { outcome: 'away', hg, ag };
    return { outcome: 'draw', hg, ag };
  }
  return { outcome: res.result || '', hg: null, ag: null };
}

function buildComparison(prediction, actual, advancedMatchMode) {
  // advancedMatchMode: 'wdl' | 'score' — only used when both sides used advanced mode
  const items = [];
  let totalEarned = 0;
  let totalPossible = 0;

  const addItem = (item) => {
    items.push(item);
    totalEarned   += item.earned;
    totalPossible += item.possible;
  };

  // ── Group stage ──
  Object.keys(GROUPS).forEach((gk) => {
    const predIsSimple   = !!(prediction.qualifiers[gk] && prediction.qualifiers[gk].length > 0);
    const actualIsSimple = !!(actual.qualifiers[gk]     && actual.qualifiers[gk].length > 0);

    // Derive ordered standings for each side
    const predOrder = predIsSimple
      ? prediction.qualifiers[gk]
      : calcStandings(gk, prediction.matchResults[gk]).map((t) => t.name);
    const actualOrder = actualIsSimple
      ? actual.qualifiers[gk]
      : calcStandings(gk, actual.matchResults[gk]).map((t) => t.name);

    // 1pt per correct group position (positions 1–4)
    GROUPS[gk].forEach((team) => {
      const predPos   = predOrder.indexOf(team);
      const actualPos = actualOrder.indexOf(team);
      if (predPos < 0 || actualPos < 0) return;
      const correct = predPos === actualPos;
      addItem({
        category: 'Group Position', group: gk,
        description: `${team} — predicted ${predPos + 1}${ord(predPos + 1)}, actual ${actualPos + 1}${ord(actualPos + 1)}`,
        correct, earned: correct ? 1 : 0, possible: 1,
      });
    });

    // Advanced mode match results — only when BOTH sides used advanced mode
    if (!predIsSimple && !actualIsSimple) {
      const matches = groupMatches(GROUPS[gk]);
      matches.forEach(([home, away], i) => {
        const predRes   = (prediction.matchResults[gk] || {})[i];
        const actualRes = (actual.matchResults[gk]     || {})[i];
        const p = getOutcome(predRes);
        const a = getOutcome(actualRes);
        if (!p.outcome || !a.outcome) return;

        const exactMatch  = p.outcome === a.outcome && p.hg === a.hg && p.ag === a.ag && p.hg !== null;
        const resultMatch = p.outcome === a.outcome;

        if (advancedMatchMode === 'score') {
          // 3pts for exact score, 0 otherwise
          const scoreStr = (r) => r.hg !== null ? `${r.hg}–${r.ag}` : r.outcome;
          addItem({
            category: 'Match Score', group: gk,
            description: `${home} vs ${away} — predicted ${scoreStr(p)}, actual ${scoreStr(a)}`,
            correct: exactMatch, exactMatch,
            earned: exactMatch ? 3 : 0, possible: 3,
          });
        } else {
          // 1pt for correct W/D/L
          const outcomeLabel = { home: `${home} win`, away: `${away} win`, draw: 'Draw' };
          addItem({
            category: 'Match Result', group: gk,
            description: `${home} vs ${away} — predicted ${outcomeLabel[p.outcome] || p.outcome}, actual ${outcomeLabel[a.outcome] || a.outcome}`,
            correct: resultMatch, exactMatch,
            earned: resultMatch ? 1 : 0, possible: 1,
          });
        }
      });
    }
  });

  // ── Knockout stage — 1pt per correct team advancing ──
  const koRounds = [
    { key: 'r32', label: 'Round of 32', count: 16 },
    { key: 'r16', label: 'Round of 16', count: 8 },
    { key: 'qf',  label: 'Quarter-final', count: 4 },
    { key: 'sf',  label: 'Semi-final', count: 2 },
  ];

  koRounds.forEach(({ key, label, count }) => {
    for (let i = 0; i < count; i++) {
      const predWinner   = prediction.knockout[key][i];
      const actualWinner = actual.knockout[key][i];
      if (predWinner === 'TBD' || actualWinner === 'TBD') continue;
      const correct = predWinner === actualWinner;
      addItem({
        category: label, group: null,
        description: `Predicted ${predWinner} to advance — actual: ${actualWinner}`,
        correct, earned: correct ? 1 : 0, possible: 1,
      });
    }
  });

  // Champion — 1pt
  if (prediction.knockout.winner !== 'TBD' && actual.knockout.winner !== 'TBD') {
    const correct = prediction.knockout.winner === actual.knockout.winner;
    addItem({
      category: 'Champion', group: null,
      description: `Predicted ${prediction.knockout.winner}, actual ${actual.knockout.winner}`,
      correct, earned: correct ? 1 : 0, possible: 1,
    });
  }

  // 3rd place — 1pt
  if (prediction.knockout.thirdPlace !== 'TBD' && actual.knockout.thirdPlace !== 'TBD') {
    const correct = prediction.knockout.thirdPlace === actual.knockout.thirdPlace;
    addItem({
      category: '3rd Place', group: null,
      description: `Predicted ${prediction.knockout.thirdPlace}, actual ${actual.knockout.thirdPlace}`,
      correct, earned: correct ? 1 : 0, possible: 1,
    });
  }

  // KO match scores — only when both sides used advanced mode with score input
  if (advancedMatchMode === 'score') {
    koRounds.forEach(({ key, label, count }) => {
      for (let i = 0; i < count / 2; i++) {
        const predA = prediction.knockout[key][i * 2];
        const predB = prediction.knockout[key][i * 2 + 1];
        const actA  = actual.knockout[key][i * 2];
        const actB  = actual.knockout[key][i * 2 + 1];
        const predScore = (prediction.knockout.scores || {})[`${key}-${i}`];
        const actScore  = (actual.knockout.scores     || {})[`${key}-${i}`];
        if (!predScore || !actScore) continue;
        const ph = parseInt(predScore.h), pa = parseInt(predScore.a);
        const ah = parseInt(actScore.h),  aa = parseInt(actScore.a);
        if (isNaN(ph) || isNaN(pa) || isNaN(ah) || isNaN(aa)) continue;
        const exactMatch = ph === ah && pa === aa;
        addItem({
          category: `${label} Score`, group: null,
          description: `${predA} vs ${predB} — predicted ${ph}–${pa}, actual ${ah}–${aa}`,
          correct: exactMatch, exactMatch,
          earned: exactMatch ? 3 : 0, possible: 3,
        });
      }
    });
  }

  return { items, totalEarned, totalPossible };
}

// ─── Comparison Panel ─────────────────────────────────────────────────────────

const ALL_CATEGORIES = ['Group Position', 'Match Result', 'Match Score', 'Round of 32', 'Round of 16', 'Quarter-final', 'Semi-final', 'Champion', '3rd Place'];

function ComparisonPanel({ prediction, actual, predGroupMode, actGroupMode }) {
  const [displayMode, setDisplayMode] = useState('correct'); // 'correct' | 'points'
  const [matchMode, setMatchMode]     = useState('wdl');     // 'wdl' | 'score'
  const [filterCategory, setFilterCategory] = useState('All');
  const [filterResult, setFilterResult]     = useState('All');
  const [filterGroup, setFilterGroup]       = useState('All');

  const bothAdvanced = predGroupMode === 'advanced' && actGroupMode === 'advanced';
  const { items, totalEarned, totalPossible } = buildComparison(prediction, actual, matchMode);

  const filtered = items.filter((item) => {
    if (filterCategory !== 'All' && item.category !== filterCategory) return false;
    if (filterResult === 'Correct'   && !item.correct) return false;
    if (filterResult === 'Incorrect' &&  item.correct) return false;
    if (filterGroup !== 'All' && String(item.group) !== String(filterGroup)) return false;
    return true;
  });

  const correctCount   = filtered.filter((i) =>  i.correct).length;
  const incorrectCount = filtered.filter((i) => !i.correct).length;
  const filteredEarned = filtered.reduce((s, i) => s + i.earned, 0);
  const hasAnyData = items.length > 0;

  return (
    <div className="comparison-panel">
      <div className="cmp-header">
        <div>
          <div className="cmp-title">📊 Prediction Analysis</div>
          <div className="cmp-sub">
            Scoring: 1pt per correct group position · 1pt per correct KO advance
            {bothAdvanced && <> · {matchMode === 'wdl' ? '1pt per correct W/D/L' : '3pts per exact score'}</>}
          </div>
        </div>
        <div style={{ display: 'flex', gap: 8, flexWrap: 'wrap', alignItems: 'center' }}>
          {bothAdvanced && (
            <div className="score-mode-toggle">
              <button className={`toggle-btn ${matchMode === 'wdl' ? 'active' : ''}`} onClick={() => setMatchMode('wdl')}>+1 W/D/L</button>
              <button className={`toggle-btn ${matchMode === 'score' ? 'active' : ''}`} onClick={() => setMatchMode('score')}>+3 Exact score</button>
            </div>
          )}
          <div className="score-mode-toggle">
            <button className={`toggle-btn ${displayMode === 'correct' ? 'active' : ''}`} onClick={() => setDisplayMode('correct')}>✓/✗</button>
            <button className={`toggle-btn ${displayMode === 'points' ? 'active' : ''}`} onClick={() => setDisplayMode('points')}>Points</button>
          </div>
        </div>
      </div>

      {!hasAnyData && (
        <div className="cmp-empty">Fill in both your predictions and actual results to see the comparison here.</div>
      )}

      {hasAnyData && (
        <>
          {/* Summary stats */}
          <div className="cmp-stats">
            <div className="cmp-stat">
              <div className="cmp-stat-val correct-col">{items.filter((i) => i.correct).length}</div>
              <div className="cmp-stat-label">Correct</div>
            </div>
            <div className="cmp-stat">
              <div className="cmp-stat-val incorrect-col">{items.filter((i) => !i.correct).length}</div>
              <div className="cmp-stat-label">Incorrect</div>
            </div>
            <div className="cmp-stat">
              <div className="cmp-stat-val">{items.length > 0 ? Math.round((items.filter((i) => i.correct).length / items.length) * 100) : 0}%</div>
              <div className="cmp-stat-label">Accuracy</div>
            </div>
            <div className="cmp-stat">
              <div className="cmp-stat-val points-col">{totalEarned} <span style={{ fontSize: 13, fontWeight: 400, color: '#888' }}>/ {totalPossible}</span></div>
              <div className="cmp-stat-label">Points</div>
            </div>
          </div>

          {/* Filters */}
          <div className="cmp-filters">
            <div className="filter-group">
              <span className="filter-label">Category</span>
              <select className="filter-select" value={filterCategory} onChange={(e) => setFilterCategory(e.target.value)}>
                <option value="All">All</option>
                {ALL_CATEGORIES.map((c) => <option key={c} value={c}>{c}</option>)}
              </select>
            </div>
            <div className="filter-group">
              <span className="filter-label">Result</span>
              <select className="filter-select" value={filterResult} onChange={(e) => setFilterResult(e.target.value)}>
                <option value="All">All</option>
                <option value="Correct">Correct only</option>
                <option value="Incorrect">Incorrect only</option>
              </select>
            </div>
            <div className="filter-group">
              <span className="filter-label">Group</span>
              <select className="filter-select" value={filterGroup} onChange={(e) => setFilterGroup(e.target.value)}>
                <option value="All">All</option>
                {'ABCDEFGHIJKL'.split('').map((g) => <option key={g} value={g}>Group {g}</option>)}
                <option value="null">Knockout only</option>
              </select>
            </div>
            <div className="filter-summary">
              {filtered.length} items · <span className="correct-col">{correctCount}✓</span> · <span className="incorrect-col">{incorrectCount}✗</span>
              {displayMode === 'points' && <> · <span className="points-col">{filteredEarned}pts</span></>}
            </div>
          </div>

          {/* Results list */}
          <div className="cmp-list">
            {filtered.length === 0 && <div className="cmp-empty">No items match your filters.</div>}
            {filtered.map((item, i) => (
              <div key={i} className={`cmp-item ${item.correct ? 'cmp-correct' : 'cmp-incorrect'} ${item.exactMatch ? 'cmp-exact' : ''}`}>
                <div className="cmp-item-left">
                  <span className={`cmp-tick ${item.correct ? 'tick-correct' : 'tick-wrong'}`}>{item.correct ? '✓' : '✗'}</span>
                  <div>
                    <div className="cmp-item-cat">
                      {item.category}
                      {item.group && <span className="cmp-item-group">Group {item.group}</span>}
                      {item.exactMatch && <span className="cmp-exact-badge">Exact score!</span>}
                    </div>
                    <div className="cmp-item-desc">{item.description}</div>
                  </div>
                </div>
                {displayMode === 'points' && (
                  <div className={`cmp-item-pts ${item.earned > 0 ? 'pts-earned' : 'pts-zero'}`}>+{item.earned}</div>
                )}
              </div>
            ))}
          </div>
        </>
      )}
    </div>
  );
}

// ─── Shared match slot (knockout) ─────────────────────────────────────────────

function MatchSlot({ teamA, teamB, label, onSelectWinner }) {
  return (
    <div className="match-slot">
      {label && <div className="match-label">{label}</div>}
      {[teamA, teamB].map((team, i) => (
        <div
          key={i}
          className={`match-team ${team !== 'TBD' && onSelectWinner ? 'clickable' : ''}`}
          style={{ borderTop: i === 1 ? '0.5px solid rgba(0,0,0,0.08)' : 'none' }}
          onClick={() => team !== 'TBD' && onSelectWinner && onSelectWinner(team)}
        >
          <span className="team-name">{team === 'TBD' ? <span className="team-tbd">TBD</span> : team}</span>
        </div>
      ))}
    </div>
  );
}

// ─── Group Stage — Simple Mode ────────────────────────────────────────────────

function SimpleGroupCard({ groupKey, qualifiers, onToggle }) {
  const teams = GROUPS[groupKey];
  const q = qualifiers[groupKey] || [];
  const sorted = [...teams].sort((a, b) => {
    const pa = q.indexOf(a), pb = q.indexOf(b);
    if (pa >= 0 && pb >= 0) return pa - pb;
    if (pa >= 0) return -1;
    if (pb >= 0) return 1;
    return a.localeCompare(b);
  });

  return (
    <div className="group-card">
      <div className="group-header">
        <span>Group {groupKey}</span>
        <span className="group-hint">click to rank</span>
      </div>
      <table className="group-table">
        <thead><tr><th></th><th style={{ textAlign: 'left' }}>Team</th><th>Pos</th></tr></thead>
        <tbody>
          {sorted.map((team) => {
            const pos = q.indexOf(team);
            return (
              <tr key={team} className={`group-row pos-${pos}`} onClick={() => onToggle(groupKey, team)}>
                <td className="badge-cell">
                  {pos === 0 && <span className="badge b1">1st</span>}
                  {pos === 1 && <span className="badge b2">2nd</span>}
                  {pos === 2 && <span className="badge b3">3rd★</span>}
                </td>
                <td className="team-cell"><span className="team-name">{team}</span></td>
                <td className="pts">{pos >= 0 ? pos + 1 : '—'}</td>
              </tr>
            );
          })}
        </tbody>
      </table>
    </div>
  );
}

// ─── Group Stage — Advanced Mode ──────────────────────────────────────────────

function AdvancedGroupCard({ groupKey, matchResults, onUpdateMatch, scoreMode }) {
  const teams = GROUPS[groupKey];
  const matches = groupMatches(teams);
  const mrs = matchResults[groupKey] || {};
  const standings = calcStandings(groupKey, mrs);

  return (
    <div className="group-card adv-card">
      <div className="group-header">
        <span>Group {groupKey}</span>
        <span className="group-hint">{scoreMode ? 'enter scores' : 'pick results'}</span>
      </div>
      <table className="group-table">
        <thead><tr><th></th><th style={{ textAlign: 'left' }}>Team</th><th>W</th><th>D</th><th>L</th><th>GF</th><th>GA</th><th>Pts</th></tr></thead>
        <tbody>
          {standings.map((team, i) => (
            <tr key={team.name} className={`group-row pos-${i < 2 ? i : i === 2 ? 2 : -1}`}>
              <td className="badge-cell">
                {i === 0 && <span className="badge b1">1st</span>}
                {i === 1 && <span className="badge b2">2nd</span>}
                {i === 2 && <span className="badge b3">3rd</span>}
                {i === 3 && <span className="badge b4">4th</span>}
              </td>
              <td className="team-cell"><span className="team-name">{team.name}</span></td>
              <td>{team.w}</td><td>{team.d}</td><td>{team.l}</td>
              <td>{team.gf}</td><td>{team.ga}</td>
              <td className="pts">{team.pts}</td>
            </tr>
          ))}
        </tbody>
      </table>
      <div className="match-list">
        <div className="match-list-header">Matches</div>
        {matches.map(([home, away], i) => {
          const res = mrs[i] || {};
          return (
            <div key={i} className="match-row">
              <span className="match-team-name home">{home}</span>
              {scoreMode ? (
                <div className="score-inputs">
                  <input type="number" min="0" max="99" className="score-input" value={res.homeGoals ?? ''} onChange={(e) => onUpdateMatch(groupKey, i, { ...res, homeGoals: e.target.value })} placeholder="0" />
                  <span className="score-sep">–</span>
                  <input type="number" min="0" max="99" className="score-input" value={res.awayGoals ?? ''} onChange={(e) => onUpdateMatch(groupKey, i, { ...res, awayGoals: e.target.value })} placeholder="0" />
                </div>
              ) : (
                <div className="wdl-btns">
                  {['home', 'draw', 'away'].map((r) => (
                    <button key={r} className={`wdl-btn ${res.result === r ? 'active-' + r : ''}`}
                      onClick={() => onUpdateMatch(groupKey, i, { ...res, result: res.result === r ? '' : r })}>
                      {r === 'home' ? 'W' : r === 'draw' ? 'D' : 'L'}
                    </button>
                  ))}
                </div>
              )}
              <span className="match-team-name away">{away}</span>
            </div>
          );
        })}
      </div>
    </div>
  );
}

// ─── Group Stage wrapper ───────────────────────────────────────────────────────

function GroupStage({ data, onSetQualifiers, onUpdateMatch, onBuildKnockout, groupMode, scoreMode, onToggleScoreMode }) {
  const q = data.qualifiers;

  const getAdvancedQualifiers = () => {
    const derived = {};
    Object.keys(GROUPS).forEach((gk) => {
      derived[gk] = calcStandings(gk, data.matchResults[gk]).map((t) => t.name);
    });
    return derived;
  };

  const allTop2Done = groupMode === 'advanced'
    ? Object.keys(GROUPS).every((g) => calcStandings(g, data.matchResults[g]).some((t) => t.pts > 0))
    : Object.keys(GROUPS).every((g) => (q[g] || []).length >= 2);
  const best3Count = groupMode === 'advanced' ? 8 : Object.values(q).filter((v) => v && v[2]).length;
  const canBuild = groupMode === 'advanced' ? true : (allTop2Done && best3Count >= 8);

  const handleToggle = (groupKey, team) => {
    const cur = [...(q[groupKey] || [])];
    const idx = cur.indexOf(team);
    let next;
    if (idx >= 0) next = cur.filter((t) => t !== team);
    else if (cur.length < 3) next = [...cur, team];
    else next = [cur[1], cur[2], team];
    onSetQualifiers(groupKey, next);
  };

  const handleBuild = () => {
    const qSource = groupMode === 'advanced' ? getAdvancedQualifiers() : q;
    const p = (g, i) => (qSource[g] || [])[i] || 'TBD';
    const slots = [];
    'ABCDEFGHIJKL'.split('').forEach((g) => { slots.push(p(g, 0)); slots.push(p(g, 1)); });
    let thirds = [];
    if (groupMode === 'advanced') {
      const thirdsList = [];
      'ABCDEFGHIJKL'.split('').forEach((g) => {
        const s = calcStandings(g, data.matchResults[g]);
        if (s[2]) thirdsList.push({ ...s[2], group: g });
      });
      thirdsList.sort((a, b) => b.pts - a.pts || (b.gf - b.ga) - (a.gf - a.ga));
      thirds = thirdsList.slice(0, 8).map((t) => t.name);
    } else {
      'ABCDEFGHIJKL'.split('').forEach((g) => { if ((q[g] || [])[2]) thirds.push(q[g][2]); });
    }
    while (thirds.length < 8) thirds.push('TBD');
    const r32 = [...slots, ...thirds.slice(0, 8)];
    while (r32.length < 32) r32.push('TBD');
    onBuildKnockout(r32);
  };

  return (
    <div>
      {groupMode === 'simple' && (
        <div className="info-bar">Click once for <strong>1st</strong>, twice for <strong>2nd</strong>, three times for <strong>best 3rd ⭐</strong>, again to deselect.</div>
      )}
      {groupMode === 'advanced' && (
        <div className="info-bar" style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', flexWrap: 'wrap', gap: 8 }}>
          <span>Enter match results — standings update automatically. Top 2 + 8 best 3rds advance.</span>
          <div className="score-mode-toggle">
            <button className={`toggle-btn ${!scoreMode ? 'active' : ''}`} onClick={() => onToggleScoreMode(false)}>W / D / L</button>
            <button className={`toggle-btn ${scoreMode ? 'active' : ''}`} onClick={() => onToggleScoreMode(true)}>Scores</button>
          </div>
        </div>
      )}
      <div className="group-grid">
        {Object.entries(GROUPS).map(([gk]) =>
          groupMode === 'simple'
            ? <SimpleGroupCard key={gk} groupKey={gk} qualifiers={q} onToggle={handleToggle} />
            : <AdvancedGroupCard key={gk} groupKey={gk} matchResults={data.matchResults} onUpdateMatch={onUpdateMatch} scoreMode={scoreMode} />
        )}
      </div>
      {groupMode === 'simple' && !allTop2Done && <p className="build-hint">Select top 2 from every group to unlock the knockout stage.</p>}
      {groupMode === 'simple' && allTop2Done && best3Count < 8 && <p className="build-hint">{best3Count}/8 best 3rd-place teams selected. Pick {8 - best3Count} more.</p>}
      <button className={`build-btn ${canBuild ? 'active' : 'disabled'}`} onClick={() => canBuild && handleBuild()}>Build knockout bracket →</button>
    </div>
  );
}

// ─── Knockout Stage ────────────────────────────────────────────────────────────

function KnockoutStage({ knockout, onUpdate }) {
  const ko = knockout;
  const advR32 = (mi, t) => { const r16 = [...ko.r16]; r16[mi] = t; onUpdate({ ...ko, r16 }); };
  const advR16 = (mi, t) => { const qf  = [...ko.qf];  qf[mi]  = t; onUpdate({ ...ko, qf  }); };
  const advQF  = (mi, t) => { const sf  = [...ko.sf];  sf[mi]  = t; onUpdate({ ...ko, sf  }); };
  const advSF  = (mi, t) => {
    const sf = [...ko.sf]; sf[mi] = t;
    const other = mi % 2 === 0 ? mi + 1 : mi - 1;
    const loser = [ko.sf[mi], ko.sf[other]].find((x) => x !== t && x !== 'TBD') || 'TBD';
    const slot = mi < 2 ? 0 : 1;
    const final = [...ko.final]; final[slot] = t;
    const third = [...ko.third]; third[slot] = loser;
    onUpdate({ ...ko, sf, final, third });
  };
  const advFinal = (t) => onUpdate({ ...ko, winner: t });
  const advThird = (t) => onUpdate({ ...ko, thirdPlace: t });

  const matchH = 80, gap0 = 6;
  const gap1 = (matchH + gap0) * 2 - matchH;
  const gap2 = (matchH + gap1) * 2 - matchH;
  const gap3 = (matchH + gap2) * 2 - matchH;
  const mt1 = (matchH + gap0) / 2;
  const mt2 = mt1 + (matchH + gap1) / 2;
  const mt3 = mt2 + (matchH + gap2) / 2;
  const mt4 = mt3 + (matchH + gap3) / 2;

  const renderCol = (label, matches, marginTop) => (
    <div className="ko-col">
      <div className="ko-col-label">{label}</div>
      <div className="ko-col-matches" style={{ marginTop }}>
        {matches.map((m, i) => <div key={i}>{i > 0 && <div style={{ height: m.gap }} />}{m.node}</div>)}
      </div>
    </div>
  );

  const mkR32 = (s) => Array.from({ length: 8 }, (_, i) => { const mi = s*8+i; return { node: <MatchSlot teamA={ko.r32[mi*2]} teamB={ko.r32[mi*2+1]} label={`R32 ${mi+1}`} onSelectWinner={(t) => advR32(mi, t)} />, gap: gap0 }; });
  const mkR16 = (s) => Array.from({ length: 4 }, (_, i) => { const mi = s*4+i; return { node: <MatchSlot teamA={ko.r16[mi*2]} teamB={ko.r16[mi*2+1]} label={`R16 ${mi+1}`} onSelectWinner={(t) => advR16(mi, t)} />, gap: gap1 }; });
  const mkQF  = (s) => Array.from({ length: 2 }, (_, i) => { const mi = s*2+i; return { node: <MatchSlot teamA={ko.qf[mi*2]}  teamB={ko.qf[mi*2+1]}  label={`QF ${mi+1}`}  onSelectWinner={(t) => advQF(mi,  t)} />, gap: gap2 }; });
  const mkSF  = (s) => [{ node: <MatchSlot teamA={ko.sf[s*2]} teamB={ko.sf[s*2+1]} label={`SF ${s+1}`} onSelectWinner={(t) => advSF(s*2, t)} />, gap: 0 }];

  return (
    <div>
      <p className="ko-hint">Click a team to advance them. SF losers auto-fill the 3rd place playoff.</p>
      <div className="ko-scroll">
        <div className="ko-bracket">
          {renderCol('Round of 32', mkR32(0), 0)}
          {renderCol('Round of 16', mkR16(0), mt1)}
          {renderCol('Quarter-finals', mkQF(0), mt2)}
          {renderCol('Semi-finals', mkSF(0), mt3)}
          <div className="ko-col ko-centre">
            <div style={{ height: mt4 }} />
            <div className="ko-col-label">Final</div>
            <MatchSlot teamA={ko.final[0]} teamB={ko.final[1]} label="🏆 Final" onSelectWinner={advFinal} />
            <div className="champion-box">
              <div className="champ-trophy">🏆</div>
              <div className="champ-label">CHAMPION</div>
              <div className="champ-team">{ko.winner === 'TBD' ? <em>TBD</em> : ko.winner}</div>
            </div>
            <div style={{ height: 20 }} />
            <div className="ko-col-label third-label">3rd Place</div>
            <MatchSlot teamA={ko.third[0]} teamB={ko.third[1]} label="🥉 3rd place" onSelectWinner={advThird} />
            {ko.thirdPlace !== 'TBD' && (
              <div className="third-box">
                <div className="champ-trophy">🥉</div>
                <div className="champ-label">3RD PLACE</div>
                <div className="champ-team">{ko.thirdPlace}</div>
              </div>
            )}
          </div>
          {renderCol('Semi-finals', mkSF(1), mt3)}
          {renderCol('Quarter-finals', mkQF(1), mt2)}
          {renderCol('Round of 16', mkR16(1), mt1)}
          {renderCol('Round of 32', mkR32(1), 0)}
        </div>
      </div>
      {(ko.winner !== 'TBD' || ko.thirdPlace !== 'TBD') && (
        <div className="result-banner">
          {ko.winner !== 'TBD' && <div className="result-item"><span>🏆</span><div><div className="result-label">CHAMPION</div><div className="result-team">{ko.winner}</div></div></div>}
          {ko.thirdPlace !== 'TBD' && <div className="result-item"><span>🥉</span><div><div className="result-label">3RD PLACE</div><div className="result-team">{ko.thirdPlace}</div></div></div>}
        </div>
      )}
    </div>
  );
}

// ─── App ───────────────────────────────────────────────────────────────────────

export default function App() {
  const [activeTab, setActiveTab] = useState('prediction');
  const [section, setSection]     = useState('groups');
  const [showComparison, setShowComparison] = useState(false);

  const [prediction, setPrediction]           = useState(emptyData());
  const [actual, setActual]                   = useState(emptyData());
  const [predGroupMode, setPredGroupMode]     = useState('simple');
  const [actGroupMode,  setActGroupMode]      = useState('simple');
  const [predScoreMode, setPredScoreMode]     = useState(false);
  const [actScoreMode,  setActScoreMode]      = useState(false);

  const data      = activeTab === 'prediction' ? prediction      : actual;
  const setData   = activeTab === 'prediction' ? setPrediction   : setActual;
  const groupMode = activeTab === 'prediction' ? predGroupMode   : actGroupMode;
  const setGMode  = activeTab === 'prediction' ? setPredGroupMode : setActGroupMode;
  const scoreMode = activeTab === 'prediction' ? predScoreMode   : actScoreMode;
  const setSMode  = activeTab === 'prediction' ? setPredScoreMode : setActScoreMode;

  const setQualifiers = (groupKey, teams) =>
    setData((prev) => ({ ...prev, qualifiers: { ...prev.qualifiers, [groupKey]: teams } }));

  const updateMatch = (groupKey, matchIdx, result) =>
    setData((prev) => ({
      ...prev,
      matchResults: { ...prev.matchResults, [groupKey]: { ...(prev.matchResults[groupKey] || {}), [matchIdx]: result } },
    }));

  const buildKnockout = (r32) => {
    setData((prev) => ({ ...prev, knockout: { ...emptyKO(), r32 } }));
    setSection('knockout');
  };

  const updateKnockout = (ko) => setData((prev) => ({ ...prev, knockout: ko }));

  return (
    <div className="app">
      <div className="hero">
        <span className="hero-icon">⚽</span>
        <div>
          <div className="hero-title">FIFA World Cup 2026</div>
          <div className="hero-sub">48 teams · 12 groups · R32 → R16 → QF → SF → Final + 3rd place</div>
        </div>
      </div>

      {/* Tab switcher + compare button */}
      <div className="tab-row">
        {[
          { id: 'prediction', label: '🔮 My Prediction', color: '#1a3c5e' },
          { id: 'actual',     label: '📺 Actual Results', color: '#6b1a1a' },
        ].map((t) => (
          <button key={t.id} className="tab-btn"
            style={{ background: activeTab === t.id ? t.color : '#fff', color: activeTab === t.id ? '#fff' : '#666' }}
            onClick={() => { setActiveTab(t.id); setShowComparison(false); }}>
            {t.label}
          </button>
        ))}
        {activeTab === 'actual' && (
          <button
            className="tab-btn compare-btn"
            style={{ marginLeft: 'auto', background: showComparison ? '#2d6a2d' : '#fff', color: showComparison ? '#fff' : '#2d6a2d', borderColor: '#2d6a2d' }}
            onClick={() => setShowComparison((v) => !v)}>
            {showComparison ? '▲ Hide analysis' : '📊 Compare with predictions'}
          </button>
        )}
      </div>

      {/* Comparison panel — shown on Actual Results tab */}
      {activeTab === 'actual' && showComparison && (
        <ComparisonPanel prediction={prediction} actual={actual} predGroupMode={predGroupMode} actGroupMode={actGroupMode} />
      )}

      {/* Section nav + mode toggle */}
      {!showComparison && (
        <>
          <div className="section-nav-row">
            <div className="section-nav">
              {[{ id: 'groups', label: 'Group Stage' }, { id: 'knockout', label: 'Knockout Stage' }].map((s) => (
                <button key={s.id} className={`section-btn ${section === s.id ? 'active' : ''}`} onClick={() => setSection(s.id)}>{s.label}</button>
              ))}
            </div>
            {section === 'groups' && (
              <div className="mode-toggle">
                <button className={`toggle-btn ${groupMode === 'simple' ? 'active' : ''}`} onClick={() => setGMode('simple')}>Simple</button>
                <button className={`toggle-btn ${groupMode === 'advanced' ? 'active' : ''}`} onClick={() => setGMode('advanced')}>Advanced</button>
              </div>
            )}
          </div>
          <div className="content">
            {section === 'groups' && (
              <GroupStage data={data} onSetQualifiers={setQualifiers} onUpdateMatch={updateMatch} onBuildKnockout={buildKnockout} groupMode={groupMode} scoreMode={scoreMode} onToggleScoreMode={setSMode} />
            )}
            {section === 'knockout' && (
              <KnockoutStage knockout={data.knockout} onUpdate={updateKnockout} />
            )}
          </div>
        </>
      )}
    </div>
  );
}
